import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate, useLocation } from 'react-router-dom';
import {
  LayoutDashboard, FolderKanban, Bell, BarChart2,
  User, LogOut, ChevronDown, Zap, Moon, Sun, Search, Trophy
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import Avatar from '../common/Avatar';
import useNotifications from '../../hooks/useNotifications';
import { useDarkMode } from '../../hooks/useDarkMode';

export default function AppLayout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const [searchVal, setSearchVal] = useState('');
  const { unreadCount } = useNotifications();
  const [dark, setDark] = useDarkMode();

  const navItems = [
    { to: '/dashboard',     icon: <LayoutDashboard size={16}/>, label: 'Dashboard' },
    { to: '/projects',      icon: <FolderKanban size={16}/>,    label: 'Projects' },
    { to: '/notifications', icon: <Bell size={16}/>,            label: 'Notifications', badge: unreadCount },
  ];

  return (
    <div className="app-shell">
      {/* Sidebar */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <div className="sidebar-logo-mark"><Zap size={15} color="#fff"/></div>
          <span className="sidebar-logo-text">WorkSync</span>
        </div>

        <div className="sidebar-section" style={{flex:1}}>
          <div className="sidebar-section-label">Menu</div>
          {navItems.map(item => (
            <NavLink key={item.to} to={item.to}
              className={({isActive}) => `nav-item${isActive?' active':''}`}>
              {item.icon}
              {item.label}
              {item.badge > 0 && <span className="nav-badge">{item.badge > 9 ? '9+' : item.badge}</span>}
            </NavLink>
          ))}
        </div>

        <div className="sidebar-bottom">
          <div style={{position:'relative'}}>
            <button className="user-card" style={{width:'100%'}} onClick={() => setUserMenuOpen(o=>!o)}>
              <Avatar name={user?.name} size="sm"/>
              <div style={{flex:1,minWidth:0,textAlign:'left'}}>
                <p className="truncate" style={{fontSize:'.82rem',fontWeight:600}}>{user?.name}</p>
                <p className="truncate text-xs text-3">{user?.email}</p>
              </div>
              <ChevronDown size={13} style={{color:'var(--text-3)',flexShrink:0}}/>
            </button>
            {userMenuOpen && (
              <div className="dropdown-menu" style={{bottom:'calc(100% + 5px)',top:'auto',left:0,right:0}}>
                <button className="dropdown-item" onClick={() => { navigate('/profile'); setUserMenuOpen(false); }}>
                  <User size={14}/> Profile
                </button>
                <hr className="dropdown-sep"/>
                <button className="dropdown-item danger" onClick={() => { logout(); navigate('/login'); }}>
                  <LogOut size={14}/> Sign out
                </button>
              </div>
            )}
          </div>
        </div>
      </aside>

      {/* Header */}
      <header className="header">
        <div className="header-left">
          <div className="header-search">
            <Search size={14}/>
            <input placeholder="Search…" value={searchVal} onChange={e=>setSearchVal(e.target.value)}/>
          </div>
        </div>
        <div className="header-right">
          <button className="btn btn-ghost btn-icon" onClick={() => setDark(d=>!d)} title="Toggle dark mode">
            {dark ? <Sun size={16}/> : <Moon size={16}/>}
          </button>
          <NavLink to="/notifications" className="btn btn-ghost btn-icon" style={{position:'relative'}}>
            <Bell size={16}/>
            {unreadCount > 0 && (
              <span style={{position:'absolute',top:4,right:4,width:7,height:7,background:'var(--primary)',borderRadius:'50%'}}/>
            )}
          </NavLink>
          <button className="btn btn-ghost btn-icon" onClick={() => navigate('/profile')}>
            <Avatar name={user?.name} size="sm"/>
          </button>
        </div>
      </header>

      <main className="main-content">
        <div className="page-content">
          <Outlet/>
        </div>
      </main>
    </div>
  );
}
